import{c as a,Q as t,j as r,m as o}from"./chunks/framework.Bj0Eefkv.js";const u=JSON.parse('{"title":"Desbravador Enterprise / 4.0","description":"","frontmatter":{},"headers":[],"relativePath":"desbravador-enterprise/index.md","filePath":"desbravador-enterprise/index.md","lastUpdated":1784161795000}'),d={name:"desbravador-enterprise/index.md"};function n(s,e,i,l,c,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="desbravador-enterprise-4-0" tabindex="-1">Desbravador Enterprise / 4.0 <a class="header-anchor" href="#desbravador-enterprise-4-0" aria-label="Permalink to &quot;Desbravador Enterprise / 4.0&quot;">​</a></h1><p><strong>Sistema:</strong> Desbravador Enterprise / 4.0<br><strong>Público:</strong> Cliente / Equipe de TI / Fornecedor de hardware</p><blockquote><p>ℹ️ O Desbravador Enterprise / 4.0 era anteriormente denominado <strong>Desbravador 4.5</strong>. Toda documentação, contratos e referências técnicas anteriores sob esse nome aplicam-se a este sistema.</p></blockquote><hr><h2 id="modalidades-de-implantacao" tabindex="-1">Modalidades de Implantação <a class="header-anchor" href="#modalidades-de-implantacao" aria-label="Permalink to &quot;Modalidades de Implantação&quot;">​</a></h2><p>O Desbravador Enterprise / 4.0 pode ser implantado em três modalidades distintas, de acordo com a infraestrutura disponível, o perfil do estabelecimento e a preferência operacional do cliente.</p><hr><h3 id="🏢-on-premise-—-instalacao-local-total" tabindex="-1">🏢 On-Premise — Instalação Local Total <a class="header-anchor" href="#🏢-on-premise-—-instalacao-local-total" aria-label="Permalink to &quot;🏢 On-Premise — Instalação Local Total&quot;">​</a></h3><p>Toda a infraestrutura — aplicação e banco de dados — fica instalada nas dependências do cliente.</p><ul><li>Servidor de aplicação Windows Server na rede local.</li><li>Servidor de banco de dados Linux (PostgreSQL 16) na rede local.</li><li>Total controle sobre hardware, rede e dados.</li><li>Manutenção de infraestrutura por conta do cliente ou fornecedor de TI contratado.</li></ul><blockquote><p><strong>Indicado para:</strong> estabelecimentos com equipe de TI própria ou contratada, que preferem controle total da infraestrutura e não dependem de conectividade externa para operação.</p></blockquote><p><a href="./local/requisitos-hardware.html">→ Ver requisitos completos — On-Premise</a></p><hr><h3 id="🔀-hibrido-—-aplicacao-local-banco-de-dados-em-nuvem" tabindex="-1">🔀 Híbrido — Aplicação Local + Banco de Dados em Nuvem <a class="header-anchor" href="#🔀-hibrido-—-aplicacao-local-banco-de-dados-em-nuvem" aria-label="Permalink to &quot;🔀 Híbrido — Aplicação Local + Banco de Dados em Nuvem&quot;">​</a></h3><p>O servidor de aplicação permanece nas dependências do cliente. O banco de dados é hospedado em nuvem (serviço gerenciado de PostgreSQL).</p><ul><li>Servidor de aplicação Windows Server na rede local.</li><li>Banco de dados PostgreSQL 16 provisionado em nuvem (ex.: AWS RDS, Azure Database, GCP Cloud SQL ou equivalente).</li><li>Servidor de Contas local obrigatório para operação dos terminais de PDV.</li><li>Reduz a necessidade de manter e escalar infraestrutura de banco de dados localmente.</li><li>Requer conexão estável com a internet e latência adequada para acesso ao banco remoto.</li></ul><blockquote><p><strong>Indicado para:</strong> estabelecimentos que desejam simplificar a gestão do banco de dados, com conectividade de internet confiável e sem restrições de latência para acesso ao banco remoto.</p></blockquote><p><a href="./hibrido/requisitos-hardware.html">→ Ver requisitos completos — Híbrido</a></p><hr><h3 id="☁️-cloud-—-instalacao-totalmente-em-nuvem" tabindex="-1">☁️ Cloud — Instalação Totalmente em Nuvem <a class="header-anchor" href="#☁️-cloud-—-instalacao-totalmente-em-nuvem" aria-label="Permalink to &quot;☁️ Cloud — Instalação Totalmente em Nuvem&quot;">​</a></h3><p>Toda a infraestrutura principal é provisionada em nuvem. No estabelecimento permanecem as estações de trabalho, os periféricos físicos e o Servidor de Contas para os terminais de PDV.</p><ul><li>Aplicação e banco de dados hospedados em nuvem Desbravador (Cloud Desbravador).</li><li>Servidor de Contas local obrigatório para operação dos terminais de PDV.</li><li>Acesso de Front-Office e Back-Office via Remote Desktop (RDP) ao Cloud Desbravador.</li><li>Operação do sistema principal dependente de conexão estável com a internet.</li></ul><blockquote><p><strong>Indicado para:</strong> estabelecimentos sem infraestrutura local de servidores, que preferem modelo de serviço gerenciado com atualizações automáticas e sem responsabilidade sobre hardware de servidor.</p></blockquote><p><a href="./cloud/requisitos-hardware.html">→ Ver requisitos completos — Cloud</a></p><hr><h2 id="comparativo-das-modalidades" tabindex="-1">Comparativo das Modalidades <a class="header-anchor" href="#comparativo-das-modalidades" aria-label="Permalink to &quot;Comparativo das Modalidades&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th style="text-align:center;">On-Premise</th><th style="text-align:center;">Híbrido</th><th style="text-align:center;">Cloud</th></tr></thead><tbody><tr><td><strong>Servidor de aplicação local</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td><td style="text-align:center;">✗</td></tr><tr><td><strong>Servidor de banco de dados local</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td></tr><tr><td><strong>Banco de dados em nuvem</strong></td><td style="text-align:center;">✗</td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td></tr><tr><td><strong>Aplicação em nuvem (Cloud Desbravador)</strong></td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td><td style="text-align:center;">✔</td></tr><tr><td><strong>Servidor de Contas (PDV) — sempre local</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td></tr><tr><td><strong>Operação sem internet</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td></tr><tr><td><strong>Manutenção de servidores pelo cliente</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">Parcial</td><td style="text-align:center;">Mínima</td></tr><tr><td><strong>Estações Front-Office / Back-Office</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td></tr><tr><td><strong>Estações PDV</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td></tr><tr><td><strong>Periféricos físicos suportados</strong></td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td></tr></tbody></table><hr><h2 id="infraestrutura-e-seguranca-de-rede" tabindex="-1">Infraestrutura e Segurança de Rede <a class="header-anchor" href="#infraestrutura-e-seguranca-de-rede" aria-label="Permalink to &quot;Infraestrutura e Segurança de Rede&quot;">​</a></h2><p>A equipe de TI responsável pela implantação deve configurar o firewall de acordo com o padrão de portas dos sistemas Desbravador.</p><p><a href="./../infraestrutura/portas-e-firewall.html">→ Padrão de Portas e Configuração de Firewall</a></p><hr><h2 id="contato-e-suporte" tabindex="-1">Contato e Suporte <a class="header-anchor" href="#contato-e-suporte" aria-label="Permalink to &quot;Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para dúvidas sobre qual modalidade é mais adequada ao seu ambiente, entre em contato com a equipe técnica da Desbravador antes de iniciar a aquisição de equipamentos.</p>',35)])])}const b=a(d,[["render",n]]);export{u as __pageData,b as default};
